    result = HtmlToMarkdown.convert('<p>Normal text with <u>underlined part</u> and more text.</p>', visitor)
    expect(result.content.to_s).to include('Normal text with')
    expect(result.content.to_s).to include('and more text.')
    expect(result.content.to_s).not_to include('underlined part')

  end

  it 'visitor_video_custom: Visitor replaces video with custom link' do
    visitor = Class.new do
      def visit_video(ctx, src)
        { custom: "[VIDEO: #{src}]" }
      end
    end.new
    result = HtmlToMarkdown.convert('<p>Watch our tutorial:</p><video src="tutorial.mp4" width="320" height="240" controls></video><p>Great content!</p>', visitor)
    expect(result.content.to_s).to include('[VIDEO: tutorial.mp4]')
    expect(result.content.to_s).to include('Watch our tutorial:')
    expect(result.content.to_s).to include('Great content!')

  end

  it 'visitor_video_skip: Visitor removes video elements entirely' do
    visitor = Class.new do
      def visit_video(ctx, src)
        'skip'
      end
    end.new
    result = HtmlToMarkdown.convert('<h2>Demo</h2><video src="demo.webm"></video><p>See the demo above.</p>', visitor)
    expect(result.content.to_s).to include('Demo')
    expect(result.content.to_s).to include('See the demo above.')
    expect(result.content.to_s).not_to include('demo.webm')

  end
end
